  }), mdx("h2", {
    "id": "그냥-좀-하자"
  }, "\uADF8\uB0E5 \uC880 \uD558\uC790"), mdx("h3", {
    "id": "그냥은-생각보다-어렵다"
  }, "'\uADF8\uB0E5'\uC740 \uC0DD\uAC01\uBCF4\uB2E4 \uC5B4\uB835\uB2E4"), mdx("p", null, "\uC0AC\uC2E4 '\uADF8\uB0E5'\uC774 \uC81C\uC77C \uC5B4\uB835\uB2E4.\n\uC6A9\uAE30 \uC5C6\uB294 \uC0AC\uB78C\uC740 \uB354\uC6B1 \uADF8\uB807\uB2E4. \uADF8\uB7EC\uB098 \uB450\uB824\uC6B4 \uB9C8\uC74C\uC774 \uB0B4 \uBC1C\uBAA9\uC744 \uC7A1\uB294 \uAC74 \uC2EB\uC5C8\uB2E4.\n\uC8FC\uBCC0\uC5D0\uB294 \uC5B8\uC81C\uB098 \uC2DC\uC791\uB3C4 \uD558\uC9C0 \uC54A\uACE0 \uD3EC\uAE30\uD55C \uC77C\uB4E4\uC774 \uB110\uBE0C\uB7EC\uC838 \uC788\uB2E4. \uB9C8\uC74C\uC18D\uC5D0 \uBD80\uCC44\uAC10\uC73C\uB85C \uB0A8\uC544 \uC788\uB294 \uC77C\uB4E4\uC774\uB2E4."), mdx("p", null, "\uAD1C\uD788 \uC548 \uB420 \uAC83 \uAC19\uC73C\uB2C8\uAE4C, \uC2DC\uC791\uD558\uB294 \uAC83\uB3C4 \uBB34\uC11C\uC6CC\uC11C \uC8FC\uC800\uD558\uB2E4 \uC2DC\uB3C4\uC870\uCC28 \uD558\uC9C0 \uC54A\uC558\uB2E4."), mdx("p", null, "\uC7AC\uBBF8\uC788\uAC8C\uB3C4 \uC2DC\uAC04\uC774 \uC9C0\uB098\uACE0 \uB098\uBA74 \uADF8\uB54C\uC758 \uB098\uB97C \uC774\uD574\uD558\uC9C0 \uBABB\uD558\uB294 \uAC83\uC740 \uD604\uC7AC\uC758 \uB098\uC600\uB2E4.\n\uADF8\uB54C \uD560 \uAC78, \uADF8\uAC70 \uD55C\uB2E4\uACE0 \uC8FD\uB294 \uAC83\uB3C4 \uC544\uB2CC\uB370 \uC880 \uD574\uBCF4\uC9C0... \uC5B8\uC81C\uB098 \uD6C4\uD68C\uD588\uB2E4."), mdx("p", null, "\uAC08\uC218\uB85D \uB098\uC544\uC9C0\uB294 \uAC8C \uC544\uB2C8\uB77C \uC624\uD788\uB824 \uB4A4\uB85C \uAC00\uB294 \uAC83 \uAC19\uC558\uB2E4. \uC798\uD588\uB358 \uC77C\uB3C4 \uC790\uC2E0\uAC10\uC774 \uC5C6\uC5B4\uC84C\uB2E4.\n\uC9C4\uC9DC \uC798\uD558\uACE0 \uC788\uB294 \uAC8C \uB9DE\uC744\uAE4C? \uC0AC\uC2E4\uC740 \uB2E4 \uC6B0\uC5F0\uC774\uB098 \uC6B4 \uC544\uB2C8\uC5C8\uC744\uAE4C?\n\uBD80\uC815\uC801\uC778 \uC9C8\uBB38\uB4E4\uC740 \uB05D\uC774 \uC5C6\uC5C8\uB2E4. "), mdx("p", null, "\uADF8\uB807\uAC8C 2\uB144 \uAC04 \uC2AC\uB7FC\uD504\uC5D0 \uBE60\uC84C\uB2E4.\n\uC544\uBB34\uAC83\uB3C4 \uD558\uAE30 \uC2EB\uC5B4\uC11C \uAC1C\uBC1C\uB3C4 \uBC18\uCBE4 \uB193\uC558\uB2E4.\n\uBC30\uC6B0\uB294 \uAC78 \uC88B\uC544\uD588\uB358 \uB098\uB294 \uB354 \uC774\uC0C1 \uC5C6\uC5C8\uB2E4.\n\uD765\uBBF8\uB3C4 \uC5C6\uACE0, \uC798\uD560 \uC790\uC2E0\uB3C4 \uC5C6\uC5B4\uC11C \uC7AC\uBBF8\uC5C6\uAC8C \uC0B4\uC558\uB2E4."), mdx("h3", {
    "id": "처음으로-그냥-해-본-것"
  }, "\uCC98\uC74C\uC73C\uB85C '\uADF8\uB0E5' \uD574 \uBCF8 \uAC83"), mdx("p", null, "\uC6B0\uC544\uD55C\uD14C\uD06C\uCF54\uC2A4\uC5D0 \uC9C0\uC6D0\uD55C \uAC83\uC740 \uCC98\uC74C\uC73C\uB85C \uC0C1\uD669\uC744 \uB530\uC9C0\uC9C0 \uC54A\uACE0 \uD574 \uBCF8 \uC77C\uC774\uB2E4.\n\uC5B4\uB290 \uB0A0 \uC608\uC804\uC5D0 \uBD24\uB358 \uACF5\uACE0\uAC00 \uAE30\uC5B5\uB098\uC11C \uC6B0\uC5F0\uD788 \uB4E4\uC5B4\uAC00 \uBD24\uB294\uB370 \uC9C0\uC6D0\uC790\uB97C \uBC1B\uACE0 \uC788\uC5C8\uB2E4.\n\uAC11\uC790\uAE30 \uC624\uAE30\uAC00 \uC0DD\uACBC\uB2E4. \uB098\uB3C4 \uBB3C\uB7EC\uC11C\uC9C0 \uC54A\uACE0 '\uADF8\uB0E5' \uD574 \uBCF4\uACE0 \uC2F6\uC5C8\uB2E4."), mdx("p", null, "\uC9C0\uC6D0\uD560 \uC2DC\uAE30\uAC00 \uC911\uAC04\uACE0\uC0AC \uAE30\uAC04\uC774\uC5C8\uC9C0\uB9CC \uC790\uAE30\uC18C\uAC1C\uC11C\uB97C \uC37C\uB2E4.\n\uD504\uB9AC\uCF54\uC2A4\uB3C4 \uD300 \uD504\uB85C\uC81D\uD2B8\uAC00 \uB9CE\uC544 \uC2DC\uAC04\uC774 \uC5C6\uC5C8\uC9C0\uB9CC \uD560 \uC218 \uC788\uB294 \uB9CC\uD07C \uD588\uB2E4.\n\uCD5C\uC885 \uCF54\uB529\uD14C\uC2A4\uD2B8 \uB0A0\uB3C4 \uC2DC\uD5D8 \uC774\uD2C0 \uC804\uC774\uC5C8\uC9C0\uB9CC '\uADF8\uB0E5 \uD574\uBCF4\uB294 \uAC70\uC57C. \uAD1C\uCC2E\uC544' \uB77C\uACE0 \uC0DD\uAC01\uD558\uBA70 \uAC14\uB2E4."), mdx("p", null, "\uD569\uACA9\uD55C \uB0A0\uC5D0\uB294 \uADF8\uC800 \uC2E0\uAE30\uD588\uB2E4. \uC9C4\uC9DC \uADF8\uB0E5 \uD558\uBA74 \uB420 \uC218\uB3C4 \uC788\uAD6C\uB098!\n\uACB0\uC2EC\uD588\uB2E4. \uB2E4\uB978 \uACF3\uC774\uB77C\uBA74 \uBAB0\uB77C\uB3C4 \uC6B0\uD14C\uCF54\uC5D0\uC11C\uB9CC\uD07C\uC740 \uC798\uD558\uACE0 \uC2F6\uC5C8\uB2E4."), mdx("h3", {
    "id": "그럼에도-그냥-주어지는-것은-없다"
  }, "\uADF8\uB7FC\uC5D0\uB3C4 '\uADF8\uB0E5' \uC8FC\uC5B4\uC9C0\uB294 \uAC83\uC740 \uC5C6\uB2E4"), mdx("p", null, "\uC6B0\uD14C\uCF54\uB97C \uC2DC\uC791\uD558\uAE30 \uC804\uC5D0, '\uC774\uC804\uC758 \uB098\uC640 \uB2E4\uB978 \uC0AC\uB78C\uC774 \uB418\uAE30'\uB77C\uB294 \uBAA9\uD45C\uB97C \uC138\uC6E0\uB2E4. \uC2AC\uB7FC\uD504\uC5D0\uC11C \uBC97\uC5B4\uB098 \uB354 \uB098\uC740 \uC0AC\uB78C\uC774 \uB418\uACE0 \uC2F6\uC5C8\uC73C\uB2C8\uAE4C."), mdx("p", null, "\uADF8\uB807\uC9C0\uB9CC \uCCAB \uC8FC\uB294 \uC0DD\uAC01\uBCF4\uB2E4 \uD798\uB4E4\uC5C8\uB2E4. \uC5ED\uC2DC \uD55C \uBC88\uC5D0 \uBC14\uB014 \uC218\uB294 \uC5C6\uC5C8\uB2E4."), mdx("p", null, "\uADF8\uB7F0 \uC0DD\uAC01\uC774 \uB4E4\uC5C8\uB2E4.\n\uC55E\uC73C\uB85C \uBE44\uC2B7\uD55C \uBD84\uC57C\uC758 \uC0AC\uB78C\uB4E4\uC744 \uC774\uB807\uAC8C \uB9CE\uC774 \uB9CC\uB0A0 \uC218 \uC788\uC744\uAE4C? \uBD84\uBA85 \uC544\uB2C8\uB2E4.\n\uADF8\uB7F0\uB370\uB3C4 \uC9C0\uAE08\uAE4C\uC9C0 \uC0B4\uB358 \uB300\uB85C \uC0B4\uACE0 \uC788\uC5C8\uB2E4. \uB098\uC11C\uAE30 \uC2EB\uC5B4\uD558\uACE0, \uBA3C\uC800 \uB2E4\uAC00\uAC00\uAE38 \uC8FC\uC800\uD588\uB2E4.\n10\uAC1C\uC6D4 \uB4A4\uC5D0\uB3C4 \uC608\uC804\uACFC \uAC19\uC740 \uC0AC\uB78C\uC774\uAE30\uB294 \uC2EB\uC5C8\uB2E4. \uC801\uC5B4\uB3C4 \uC5B4\uC81C\uC758 \uB098\uBCF4\uB2E4\uB294 \uB098\uC544\uC838\uC57C \uD588\uB2E4!"), mdx("p", null, "\uC644\uC804 \uB2E4\uB978 \uC0AC\uB78C\uC73C\uB85C \uD3C9\uC0DD \uC0AC\uB294 \uAC74 \uD798\uB4E4\uC9C0\uB9CC 10\uAC1C\uC6D4 \uB3D9\uC548 \uBC14\uB00C\uB294 \uAC74 \uC27D\uC9C0 \uC54A\uC744\uAE4C?\n\uC774\uBC88 \uAE30\uD68C\uC5D0 \uC2DC\uC791\uD558\uAE30 \uC5B4\uB824\uC6E0\uB358 \uAC83\uB4E4\uC744 \uB9DD\uC124\uC784 \uC5C6\uC774 \uB3C4\uC804\uD574\uBCF4\uC790\uACE0 \uB2E4\uC9D0\uD588\uB2E4."), mdx("p", null, "\uC0AC\uB78C\uB4E4\uC5D0\uAC8C \uBA3C\uC800 \uC778\uC0AC\uD558\uACE0, \uB9D0\uC744 \uAC78\uC5C8\uB2E4. \uC8FC\uC800\uD558\uC9C0 \uC54A\uACE0 \uB9D0\uD558\uB294 \uBC29\uBC95\uC744 \uC5F0\uC2B5\uD588\uB2E4.\n\uB2E4\uB4E4 \uB9D0 \uAC78\uAE30 \uC804\uC5D0\uB294 \uBB34\uC11C\uC6B4(?) \uC0AC\uB78C\uB4E4\uC778 \uC904 \uC54C\uC558\uB294\uB370 \uC804\uD600 \uC544\uB2C8\uC5C8\uB2E4.\n\uD06C\uB8E8\uB4E4\uACFC \uD558\uB294 \uD1A0\uB860, \uC774\uC57C\uAE30, \uBB50\uB4E0 \uC88B\uC558\uB2E4.\n\uC9C0\uAE08\uC740 \uD06C\uB8E8\uB4E4\uACFC \uC0DD\uD65C\uD558\uB294 \uAC8C \uC815\uB9D0 \uC7AC\uBC0C\uB2E4. \uBC29\uD559\uC774 \uC544\uC26C\uC6B8 \uC815\uB3C4\uB2E4."), mdx("p", null, "\uBB34\uC5C7\uBCF4\uB2E4 \uD63C\uC790 \uCC3E\uC544\uBCF4\uC9C0 \uC54A\uACE0 \uB2E4\uB978 \uC0AC\uB78C\uC758 \uC758\uACAC\uC744 \uBB3C\uC5B4\uBCF4\uAC8C \uB41C \uAC83\uC774 \uAC00\uC7A5 \uD070 \uBCC0\uD654\uC600\uB2E4.\n\uC5EC\uB7EC \uC0AC\uB78C\uC758 \uC758\uACAC\uC744 \uB4E3\uACE0 \uD310\uB2E8\uD560 \uC218 \uC788\uB294 \uC0AC\uB78C\uC774 \uB418\uC5B4 \uAC00\uACE0 \uC788\uC5B4 \uAE30\uC058\uB2E4."), mdx("p", null, "\uD55C \uB2EC\uC774 \uC9C0\uB09C \uC9C0\uAE08 \uB3CC\uC544\uBCF4\uBA74, \uB098\uB294 \uC5B8\uC81C\uB098 \uC5B4\uC81C\uC758 \uB098\uBCF4\uB2E4 \uB098\uC740 \uC0AC\uB78C\uC774 \uB418\uC5B4 \uC788\uC5C8\uB2E4."), mdx("h3", {
    "id": "just-do-it"
  }, "Just Do It!"), mdx("p", null, "\uBA38\uB9BF\uC18D\uC5D0\uC11C \uB9F4\uB3C4\uB294 \uC0DD\uAC01\uB4E4\uC744 \uD558\uC9C0 \uC54A\uC73C\uBA74 \uB9C8\uC74C\uC774 \uD3B8\uD574\uC9C4\uB2E4."), mdx("p", null, mdx("inlineCode", {
